mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT T.TEAM_IDX TEAM_IDX, T.TEAM_NAME TEAM_NAME, T.TEAM_MANAGER TEAM_MANAGER, T.TEAM_CONTENT TEAM_CONTENT, T.TEAM_LOCATION TEAM_LOCATION, T.TEAM_REGDATE TEAM_REGDATE, M.MEMBER_NAME MEMBER_NAME, (SELECT L.LEAGUE_NAME FROM TEAM_LEAGUE TL JOIN LEAGUE L ON TL.LEAGUE_IDX = L.LEAGUE_IDX WHERE TL.TEAM_IDX = T.TEAM_IDX AND TL.JOIN_STATUS = 1 AND ROWNUM = 1) LEAGUE_NAME FROM TEAM T JOIN MEMBER M ON T.TEAM_MANAGER = M.MEMBER_IDX
AND (T.TEAM_NAME LIKE '%' || #{keyword} || '%' OR T.TEAM_LOCATION LIKE '%' || #{keyword} || '%')
ORDER BY T.TEAM_IDX DESC ) A WHERE ROWNUM <= #{offset} + #{numOfRows} ) WHERE RN > #{offset}

mapper.update:
UPDATE MEMBER_TEAM
SET    POSITION   = #{position},
       BACK_NUM   = #{back_num, jdbcType=NUMERIC}
WHERE  MEMBER_IDX = #{member_idx}
AND    TEAM_IDX   = #{team_idx}

UPDATE MEMBER_TEAM
SET    JOIN_STATUS = #{join_status}
WHERE  MEMBER_IDX  = #{member_idx}
AND    TEAM_IDX    = #{team_idx}

